import React, { useState } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer,
} from "recharts";

export default function App() {
  const [file, setFile] = useState(null);
  const [fileId, setFileId] = useState("");
  const [summary, setSummary] = useState(null);
  const [chartData, setChartData] = useState([]);
  const [chartColumn, setChartColumn] = useState("");
  const [insights, setInsights] = useState([]);
  const [history, setHistory] = useState([]);
  const handleUpload = async () => {
    if (!file) {
      alert("Please select CSV file first");
      return;
    }

    try {
      // ✅ upload
      const formData = new FormData();
      formData.append("file", file);

      const uploadRes = await fetch("http://127.0.0.1:8000/api/upload", {
        method: "POST",
        body: formData,
      });

      const uploadData = await uploadRes.json();
      const uploadedFileId = uploadData.file_id;
      setFileId(uploadedFileId);

      // ✅ analyze
      const analyzeRes = await fetch(
        `http://127.0.0.1:8000/api/analyze/${uploadedFileId}`,
        { method: "POST" }
      );

      const analyzeData = await analyzeRes.json();
      setSummary(analyzeData.summary);

      // ✅ charts
      const chartRes = await fetch(
        `http://127.0.0.1:8000/api/charts/${uploadedFileId}`
      );

      const chartJson = await chartRes.json();
      setChartData(chartJson.data || []);
      setChartColumn(chartJson.chart_column || "");

      // ✅ insights
      const insightRes = await fetch(
        `http://127.0.0.1:8000/api/insights/${uploadedFileId}`
      );

      const insightJson = await insightRes.json();
      setInsights(insightJson.insights || []);
    } catch (error) {
      console.error("Upload flow error:", error);
      alert("Something went wrong");
    }
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>AI CSV Analyzer Dashboard 📊</h1>

      <input
        type="file"
        accept=".csv"
        onChange={(e) => setFile(e.target.files[0])}
      />

      <button onClick={handleUpload} style={{ marginLeft: "10px" }}>
        Upload & Analyze
      </button>

      {fileId && (
        <p style={{ marginTop: "15px" }}>
          <b>File ID:</b> {fileId}
        </p>
      )}

      {summary && (
        <div style={{ marginTop: "20px" }}>
          <h2>Summary</h2>
          <p><b>Rows:</b> {summary.rows}</p>
          <p><b>Columns:</b> {summary.columns.join(", ")}</p>
          <p><b>Duplicates:</b> {summary.duplicates}</p>
        </div>
      )}

      {chartData.length > 0 && (
        <div style={{ marginTop: "30px" }}>
          <h2>{chartColumn} Trend 📈</h2>

          <ResponsiveContainer width="100%" height={400}>
            <LineChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey={chartData[0]?.date ? "date" : "index"} />
              <YAxis />
              <Tooltip />
              <Line type="monotone" dataKey={chartColumn} strokeWidth={3} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}

      {insights.length > 0 && (
        <div style={{ marginTop: "30px" }}>
          <h2>AI Insights 🤖</h2>
          <ul>
            {insights.map((item, index) => (
              <li key={index}>{item}</li>
            ))}
          </ul>
        </div>
      )}

      {fileId && (
        <div style={{ marginTop: "30px" }}>
          <a
            href={`http://127.0.0.1:8000/api/export/${fileId}`}
            target="_blank"
            rel="noreferrer"
          >
            <button>Download Report 📥</button>
          </a>
        </div>
      )}
    </div>
  );
}
